import React from 'react';

function Footer() {
  return (
    <footer style={{
      background: '#0a0a0a',
      color: '#666',
      textAlign: 'center',
      padding: '20px 0',
      borderTop: '1px solid #333',
      width: '100%'
    }}>
   
    </footer>
  );
}

export default Footer;
